const BG = ['#fff3ee','#fefae8','#e6f7f5','#fef0f8','#e8f4fd','#f0fdf4']
const font = { fontFamily: "'Montserrat', sans-serif" }

function distanceMiles(lat1, lon1, lat2, lon2) {
  const R = 3958.8
  const dLat = (lat2 - lat1) * Math.PI / 180
  const dLon = (lon2 - lon1) * Math.PI / 180
  const a = Math.sin(dLat/2)**2 +
    Math.cos(lat1 * Math.PI/180) * Math.cos(lat2 * Math.PI/180) * Math.sin(dLon/2)**2
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a))
}

function InstagramIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
      <rect x="2" y="2" width="20" height="20" rx="5" stroke="currentColor" strokeWidth="2"/>
      <circle cx="12" cy="12" r="4" stroke="currentColor" strokeWidth="2"/>
      <circle cx="17.5" cy="6.5" r="1.2" fill="currentColor"/>
    </svg>
  )
}

// Cache restaurants in module scope so they survive navigation
let cachedRestaurants = null

export default function ExplorePage() {
  const { user } = useAuth()
  const [restaurants, setRestaurants] = useState(cachedRestaurants || [])
  const [favIds, setFavIds]           = useState(new Set())
  const [activeFilters, setFilters]   = useState(new Set())
  const [activeCuisines, setCuisines] = useState(new Set())
  const [loading, setLoading]         = useState(!cachedRestaurants)
  const [search, setSearch]           = useState(() => localStorage.getItem('lf_search') || '')
  const [geolocating, setGeolocating]   = useState(false)
  const [suggestions, setSuggestions]   = useState([])
  const [showSuggestions, setShowSuggestions] = useState(false)
  const [searchLabel, setSearchLabel]   = useState(() => localStorage.getItem('lf_search_label') || '')
  const [lookingUp, setLookingUp]       = useState(false)
  const zipCoordsCache = {}
  const [hasSearched, setHasSearched] = useState(() => localStorage.getItem('lf_hassearched') === 'true')
  const [radius, setRadius]           = useState(() => Number(localStorage.getItem('lf_radius')) || 5)
  const [searchState, setSearchState] = useState(() => localStorage.getItem('lf_search_state') || '') // set when a town is picked from suggestions
  // The lat/lon center of the picked town, so town search can measure real distance (not just exact-name match)
  const [searchCenter, setSearchCenter] = useState(() => {
    try { const s = localStorage.getItem('lf_search_center'); return s ? JSON.parse(s) : null } catch { return null }
  })
  const fetchedFavs = useRef(false)

  // Let the Explore tab reset us to the home view even when already on this page
  useEffect(() => {
    function goHome() { clearSearch() }
    window.addEventListener('lf-go-home', goHome)
    return () => window.removeEventListener('lf-go-home', goHome)
  }, [])

  useEffect(() => {
    // Invalidate cache if a restaurant was just added
    if (window.__lf_invalidate_restaurants) {
      cachedRestaurants = null
      window.__lf_invalidate_restaurants = false
    }

    if (cachedRestaurants) {
      setRestaurants(cachedRestaurants)
      setLoading(false)
      return
    }

    let cancelled = false
    // Safety net — never show loading forever
    const timeout = setTimeout(() => {
      if (!cancelled) {
        setLoading(false)
        console.warn('Restaurant fetch timed out')
      }
    }, 8000)

    async function fetchRestaurants() {
      try {
        // Wait for Supabase session to be ready
        await supabase.auth.getSession()
        if (cancelled) return

        const { data, error } = await supabase
          .from('restaurants')
          .select('*, amenities(*)')
          .order('name')

        if (cancelled) return
        if (error) {
          console.error('Error loading restaurants:', error)
          // Retry once after 2 seconds on error
          setTimeout(() => {
            if (!cancelled) fetchRestaurants()
          }, 2000)
          return
        }
        const list = data || []
        cachedRestaurants = list
        setRestaurants(list)
        setLoading(false)
        clearTimeout(timeout)
      } catch (e) {
        console.error('Restaurant fetch failed:', e)
        if (!cancelled) setLoading(false)
        clearTimeout(timeout)
      }
    }

    fetchRestaurants()
    return () => { cancelled = true; clearTimeout(timeout) }
  }, [])

  // When returning to app after background, refresh if cache is stale
  useEffect(() => {
    let hiddenAt = null
    function handleVisibility() {
      if (document.visibilityState === 'hidden') {
        hiddenAt = Date.now()
      } else if (document.visibilityState === 'visible') {
        const hiddenMs = hiddenAt ? Date.now() - hiddenAt : 0
        // If away for more than 5 minutes, clear cache and re-fetch
        if (hiddenMs > 5 * 60 * 1000) {
          cachedRestaurants = null
          fetchedFavs.current = false
          setLoading(true)
          supabase
            .from('restaurants')
            .select('*, amenities(*)')
            .order('name')
            .then(({ data }) => {
              const list = data || []
              cachedRestaurants = list
              setRestaurants(list)
              setLoading(false)
            })
            .catch(() => setLoading(false))
        }
        hiddenAt = null
      }
    }
    document.addEventListener('visibilitychange', handleVisibility)
    return () => document.removeEventListener('visibilitychange', handleVisibility)
  }, [])

  useEffect(() => {
    if (!user || fetchedFavs.current) return
    fetchedFavs.current = true
    supabase
      .from('favorites')
      .select('restaurant_id')
      .eq('user_id', user.id)
      .then(({ data }) => {
        setFavIds(new Set((data || []).map(f => f.restaurant_id)))
      })
  }, [user])

  function handleSearchChange(val) {
    setSearch(val)
    setSearchLabel(val)
    setSearchState('')
    setSearchCenter(null)
    localStorage.removeItem('lf_search_state')
    localStorage.removeItem('lf_search_center')
    localStorage.setItem('lf_search', val)
    localStorage.setItem('lf_search_label', val)
    if (val.trim().length === 0) {
      setHasSearched(false)
      setSuggestions([])
      setShowSuggestions(false)
      localStorage.setItem('lf_hassearched', 'false')
    } else {
      clearTimeout(suggestTimer.current)
      suggestTimer.current = setTimeout(() => fetchSuggestions(val), 300)
    }
  }

  async function submitSearch() {
    setShowSuggestions(false)
    const val = search.trim()
    if (!val) return
    setSearchState('')
    setSearchCenter(null)
    localStorage.removeItem('lf_search_state')
    localStorage.removeItem('lf_search_center')
    const isZip = /^\d{5}$/.test(val)
    // If it's not a zip and we have suggestions, use the first one
    if (!isZip && suggestions.length > 0) {
      await selectSuggestion(suggestions[0])
      return
    }
    // If it's not a zip and not in our coords, look it up
    if (!isZip && !ZIP_COORDS[val]) {
      setLookingUp(true)
      try {
        const res = await fetch(
          `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(val)}&countrycodes=us&limit=1&format=json&addressdetails=1`,
          { headers: { 'Accept-Language': 'en' } }
        )
        const data = await res.json()
        if (data[0]?.address?.postcode) {
          const zip = data[0].address.postcode.split('-')[0]
          const city = data[0].address?.city || data[0].address?.town || data[0].address?.village || ''
          const state = data[0].address?.state || ''
          ZIP_COORDS[zip] = [parseFloat(data[0].lat), parseFloat(data[0].lon)]
          setSearch(zip)
          setSearchLabel([city, state, zip].filter(Boolean).join(', '))
          localStorage.setItem('lf_search', zip)
        }
      } catch (e) {}
      setLookingUp(false)
    }
    setHasSearched(true)
    localStorage.setItem('lf_hassearched', 'true')
  }

  function handleQuickSearch(val) {
    setSearch(val)
    setSearchLabel(val)
    setSearchState('')
    setSearchCenter(null)
    localStorage.removeItem('lf_search_state')
    localStorage.removeItem('lf_search_center')
    setHasSearched(true)
    setSuggestions([])
    setShowSuggestions(false)
    localStorage.setItem('lf_search', val)
    localStorage.setItem('lf_search_label', val)
    localStorage.setItem('lf_hassearched', 'true')
  }

  function clearSearch() {
    setSearch('')
    setSearchLabel('')
    setSearchState('')
    setSearchCenter(null)
    setSuggestions([])
    setShowSuggestions(false)
    localStorage.removeItem('lf_search_label')
    localStorage.removeItem('lf_search_state')
    localStorage.removeItem('lf_search_center')
    setHasSearched(false)
    setFilters(new Set())
    setCuisines(new Set())
    localStorage.removeItem('lf_search')
    localStorage.removeItem('lf_hassearched')
    localStorage.removeItem('lf_radius')
  }

  function updateRadius(r) {
    setRadius(r)
    localStorage.setItem('lf_radius', String(r))
  }

  function toggleFilter(id) {
    setFilters(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n })
  }

  function toggleCuisine(c) {
    setCuisines(prev => { const n = new Set(prev); n.has(c) ? n.delete(c) : n.add(c); return n })
  }

  async function toggleFav(e, r) {
    e.preventDefault()
    if (!user) { alert('Sign in to save favorites!'); return }
    const wasFaved = favIds.has(r.id)
    setFavIds(prev => { const n = new Set(prev); wasFaved ? n.delete(r.id) : n.add(r.id); return n })
    if (wasFaved) {
      await supabase.from('favorites').delete().eq('user_id', user.id).eq('restaurant_id', r.id)
    } else {
      await supabase.from('favorites').insert({ user_id: user.id, restaurant_id: r.id })
    }
  }

  // Suggest only towns we actually have restaurants in — instant, works on partial typing,
  // and never suggests a town with nothing to show.
  const suggestTimer = useRef(null)
  function fetchSuggestions(val) {
    const q = val.trim().toLowerCase()
    if (q.length < 1) { setSuggestions([]); setShowSuggestions(false); return }
    const starts = []
    const contains = []
    for (const t of townOptions) {
      const city = t.city.toLowerCase()
      const label = t.label.toLowerCase()
      if (city.startsWith(q) || label.startsWith(q)) starts.push(t)
      else if (city.includes(q) || label.includes(q)) contains.push(t)
    }
    const results = [...starts, ...contains].slice(0, 8)
    setSuggestions(results)
    setShowSuggestions(results.length > 0)
  }

  async function handleSearchInput(val) {
    setSearch(val)
    setSearchLabel(val)
    localStorage.setItem('lf_search', val)
    localStorage.setItem('lf_search_label', val)
    // Clear searched state when input changes
    if (!val.trim()) {
      localStorage.setItem('lf_hassearched', 'false')
    }
    // Debounce suggestions
    clearTimeout(suggestTimer.current)
    suggestTimer.current = setTimeout(() => fetchSuggestions(val), 300)
  }

  function selectSuggestion(suggestion) {
    setShowSuggestions(false)
    setSuggestions([])
    setLookingUp(false)
    setSearchLabel(suggestion.label)
    setSearch(suggestion.city)
    setSearchState(suggestion.state || '')
    const center = (suggestion.lat != null && suggestion.lon != null) ? [suggestion.lat, suggestion.lon] : null
    setSearchCenter(center)
    localStorage.setItem('lf_search', suggestion.city)
    localStorage.setItem('lf_search_label', suggestion.label)
    localStorage.setItem('lf_search_state', suggestion.state || '')
    if (center) localStorage.setItem('lf_search_center', JSON.stringify(center))
    else localStorage.removeItem('lf_search_center')
    localStorage.setItem('lf_hassearched', 'true')
    setHasSearched(true)
  }

  async function useMyLocation() {
    setGeolocating(true)
    try {
      // On a real phone, ask iOS/Android for permission first.
      // (On the website this is skipped — the browser asks automatically.)
      if (Capacitor.isNativePlatform()) {
        const perm = await Geolocation.requestPermissions()
        if (perm.location === 'denied') {
          alert('Location access is off. You can turn it on for Little Foodies in your phone Settings, or just enter your zip code.')
          return
        }
      }

      // Get the position. The timeout means this can never hang forever —
      // if the phone can't get a fix in 10 seconds, it gives up cleanly.
      const pos = await Geolocation.getCurrentPosition({
        enableHighAccuracy: false,
        timeout: 10000,
        maximumAge: 0,
      })
      const { latitude, longitude } = pos.coords

      // Use OpenStreetMap Nominatim for free reverse geocoding
      const res = await fetch(
        `https://nominatim.openstreetmap.org/reverse?lat=${latitude}&lon=${longitude}&format=json`,
        { headers: { 'Accept-Language': 'en' } }
      )
      const data = await res.json()
      const zip = data.address?.postcode?.split('-')[0]
      if (zip) {
        const city = data.address?.city || data.address?.town || data.address?.village || ''
        const state = data.address?.state || ''
        const label = [city, state, zip].filter(Boolean).join(', ')
        setSearchLabel(label)
        localStorage.setItem('lf_search_label', label)
        handleQuickSearch(zip)
      } else {
        alert('Could not find a zip code for your location. Try entering it manually.')
      }
    } catch (e) {
      console.error('Location error:', e)
      alert('Could not get your location. Please enter your zip code manually.')
    } finally {
      // Always stop the spinner, no matter what happened above.
      setGeolocating(false)
    }
  }

  // The unique towns we actually have restaurants in — powers instant suggestions.
  // Each town also gets a center coordinate (from the first restaurant whose zip we know),
  // so picking a town can drive a real distance search.
  const townOptions = useMemo(() => {
    const byTown = new Map()
    for (const r of restaurants) {
      if (!r.city) continue
      const st = r.state || ''
      const key = `${r.city.toLowerCase()}|${st.toLowerCase()}`
      let t = byTown.get(key)
      if (!t) {
        t = { label: [r.city, st].filter(Boolean).join(', '), city: r.city, state: st, lat: null, lon: null }
        byTown.set(key, t)
      }
      if (t.lat == null) {
        const c = ZIP_COORDS[r.zip]
        if (c) { t.lat = c[0]; t.lon = c[1] }
      }
    }
    return [...byTown.values()].sort((a, b) => a.label.localeCompare(b.label))
  }, [restaurants])

  // The unique cuisines we actually have restaurants in — powers the cuisine filter chips.
  const cuisineOptions = useMemo(() => {
    const set = new Set()
    for (const r of restaurants) {
      if (r.cuisine && r.cuisine.trim()) set.add(r.cuisine.trim())
    }
    return [...set].sort((a, b) => a.localeCompare(b))
  }, [restaurants])

  const term = search.trim().toLowerCase()
  const cityMode = !!searchState
  const searchCoords = ZIP_COORDS[term] || null

  const visible = restaurants.filter(r => {
    if (!term) return false
    if (cityMode) {
      // A town was picked from suggestions.
      const sameTown = (r.city || '').toLowerCase() === term
        && (r.state || '').toLowerCase() === searchState.toLowerCase()
      if (searchCenter) {
        // Always include the searched town itself...
        if (sameTown) return true
        // ...plus any restaurant within the chosen radius of the town's center.
        const rCoords = ZIP_COORDS[r.zip]
        if (rCoords) return distanceMiles(searchCenter[0], searchCenter[1], rCoords[0], rCoords[1]) <= radius
        return false
      }
      // No center known for this town — fall back to exact-town match.
      return sameTown
    }
    if (searchCoords) {
      const rCoords = ZIP_COORDS[r.zip]
      if (rCoords) return distanceMiles(searchCoords[0], searchCoords[1], rCoords[0], rCoords[1]) <= radius
      return (r.zip || '').includes(term)
    }
    return (r.zip || '').toLowerCase().includes(term)
  }).filter(r => {
    // Amenity filters: restaurant must have ALL selected amenities.
    if (activeFilters.size) {
      const ok = [...activeFilters].every(f =>
        (r.amenities || []).some(a => a.amenity_key === f && a.yes_votes > a.no_votes)
      )
      if (!ok) return false
    }
    // Cuisine filters: restaurant's cuisine must match ANY selected cuisine.
    if (activeCuisines.size) {
      if (!activeCuisines.has((r.cuisine || '').trim())) return false
    }
    return true
  })

  const noResults = hasSearched && term && !loading && restaurants.length > 0 && visible.length === 0

  return (
    <div style={{ ...font, background: '#f9fafb', minHeight: '100vh', paddingBottom: 80 }}>

      {/* HOME */}
      {!hasSearched && (
        <div style={{ background: '#fff' }}>
          <div style={{ padding: '48px 24px 20px', textAlign: 'center' }}>
            <img src={LOGO} alt="Little Foodies" style={{ height: 80, width: 'auto', marginBottom: 16 }} />
            <p style={{ fontSize: 16, color: '#6b7280', lineHeight: 1.5, fontWeight: 500, maxWidth: 280, margin: '0 auto 28px' }}>
              Because every family deserves a great meal out.
            </p>
          </div>

          <div style={{ padding: '0 20px 24px' }}>
            <div style={{ position: 'relative' }}>
              <span style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', fontSize: 18, pointerEvents: 'none' }}>🔍</span>
              <input type="search" value={searchLabel}
                onChange={e => handleSearchChange(e.target.value)}
                onKeyDown={e => {
                  if (e.key === 'Enter') { setShowSuggestions(false); submitSearch() }
                  if (e.key === 'Escape') setShowSuggestions(false)
                }}
                onFocus={() => suggestions.length > 0 && setShowSuggestions(true)}
                onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                placeholder="City, neighborhood, or zip code…"
                style={{ width: '100%', padding: '14px 100px 14px 44px', border: '2px solid #f57b46',
                  borderRadius: 14, fontSize: 16, outline: 'none', background: '#fff',
                  boxSizing: 'border-box', ...font, boxShadow: '0 4px 20px rgba(245,123,70,.15)' }}
              />
              <button onClick={() => { setShowSuggestions(false); submitSearch() }}
                style={{ position: 'absolute', right: 8, top: '50%', transform: 'translateY(-50%)',
                  padding: '8px 16px', background: '#f57b46', border: 'none', borderRadius: 10,
                  color: '#fff', fontSize: 13, fontWeight: 600, cursor: 'pointer', ...font }}>
                Search
              </button>
              {/* Autocomplete dropdown */}
              {showSuggestions && suggestions.length > 0 && (
                <div style={{ position: 'absolute', top: '100%', left: 0, right: 0,
                  background: '#fff', border: '1.5px solid #e5e7eb', borderRadius: 14,
                  boxShadow: '0 8px 24px rgba(0,0,0,.12)', zIndex: 200, marginTop: 6,
                  overflow: 'hidden' }}>
                  {suggestions.map((s, i) => (
                    <button key={i} onMouseDown={() => selectSuggestion(s)}
                      style={{ width: '100%', padding: '12px 16px', background: 'none',
                        border: 'none', borderBottom: i < suggestions.length-1 ? '0.5px solid #f3f4f6' : 'none',
                        textAlign: 'left', cursor: 'pointer', display: 'flex',
                        alignItems: 'center', gap: 10, ...font }}>
                      <span style={{ fontSize: 16 }}>📍</span>
                      <div>
                        <div style={{ fontSize: 14, fontWeight: 600, color: '#111827' }}>{s.label}</div>
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
            <div style={{ display: 'flex', gap: 8, marginTop: 12, flexWrap: 'wrap', alignItems: 'center' }}>
              <button onClick={useMyLocation} disabled={geolocating}
                style={{ padding: '6px 13px', background: geolocating ? '#f3f4f6' : '#fff3ee',
                  border: '1px solid #fdc9b0', borderRadius: 20, fontSize: 12, fontWeight: 600,
                  color: '#f57b46', cursor: geolocating ? 'not-allowed' : 'pointer',
                  ...font, display: 'flex', alignItems: 'center', gap: 5 }}>
                {geolocating ? '⏳ Finding you…' : '📍 Use my location'}
              </button>
            </div>
          </div>

          <div style={{ padding: '0 20px', display: 'flex', flexDirection: 'column', gap: 12 }}>
            {[
              { icon: '✓', color: '#00a994', bg: '#e6f7f5', border: '#99ddd6', title: 'Community verified', desc: 'Real parents confirm high chairs, changing tables, kids menus & more' },
              { icon: '🏅', color: '#f57b46', bg: '#fff3ee', border: '#fdc9b0', title: 'Earn points', desc: 'Vote on amenities, add restaurants, write reviews — earn rewards' },
              { icon: '🎉', color: '#0692e5', bg: '#e8f4fd', border: '#9ed4f6', title: 'Family events', desc: 'Find family nights, cooking classes and kids events near you' },
            ].map(f => (
              <div key={f.title} style={{ display: 'flex', gap: 12, alignItems: 'flex-start',
                padding: '12px 14px', background: f.bg, border: '0.5px solid ' + f.border, borderRadius: 12 }}>
                <div style={{ width: 36, height: 36, borderRadius: 10, background: '#fff',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 16, flexShrink: 0, color: f.color, fontWeight: 700 }}>{f.icon}</div>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 600, color: '#111827', marginBottom: 2 }}>{f.title}</div>
                  <div style={{ fontSize: 11, color: '#6b7280', lineHeight: 1.5 }}>{f.desc}</div>
                </div>
              </div>
            ))}
          </div>

          <div style={{ padding: '28px 20px 20px', textAlign: 'center', borderTop: '0.5px solid #f3f4f6', marginTop: 24 }}>
            <a href="https://www.instagram.com/littlefoodiesapp/" target="_blank" rel="noopener noreferrer"
              style={{ display: 'inline-flex', alignItems: 'center', gap: 8, textDecoration: 'none',
                color: '#6b7280', padding: '10px 20px', borderRadius: 20, border: '1px solid #e5e7eb',
                background: '#fff', fontSize: 13, fontWeight: 600, ...font }}>
              <span style={{ color: '#e1306c', display: 'flex', alignItems: 'center' }}><InstagramIcon /></span>
              Follow us @littlefoodiesapp
            </a>
          </div>
        </div>
      )}

      {/* SEARCH RESULTS */}
      {hasSearched && (
        <>
          <div style={{ background: '#fff', padding: '12px 16px', borderBottom: '0.5px solid #e5e7eb', position: 'sticky', top: 0, zIndex: 10 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
              <img src={LOGO} alt="Little Foodies" onClick={clearSearch}
                style={{ height: 28, width: 'auto', cursor: 'pointer' }} />
              <div style={{ flex: 1 }} />
              <button onClick={clearSearch}
                style={{ fontSize: 11, color: '#f57b46', fontWeight: 600, background: 'none', border: 'none', cursor: 'pointer', ...font }}>
                ← Home
              </button>
            </div>
            <div style={{ position: 'relative' }}>
              <span style={{ position: 'absolute', left: 11, top: '50%', transform: 'translateY(-50%)', fontSize: 14, pointerEvents: 'none' }}>🔍</span>
              <input type="search" value={searchLabel}
                onChange={e => handleSearchChange(e.target.value)}
                onKeyDown={e => {
                  if (e.key === 'Enter') { setShowSuggestions(false); submitSearch() }
                  if (e.key === 'Escape') setShowSuggestions(false)
                }}
                onFocus={() => suggestions.length > 0 && setShowSuggestions(true)}
                onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                placeholder="City, neighborhood, or zip code…"
                style={{ width: '100%', padding: '9px 70px 9px 33px', border: '1.5px solid #f57b46',
                  borderRadius: 10, fontSize: 16, outline: 'none', background: '#fff',
                  boxSizing: 'border-box', ...font }}
              />
              <button onClick={submitSearch}
                style={{ position: 'absolute', right: search ? 28 : 6, top: '50%', transform: 'translateY(-50%)',
                  padding: '5px 10px', background: '#f57b46', border: 'none', borderRadius: 8,
                  color: '#fff', fontSize: 11, fontWeight: 600, cursor: 'pointer', ...font }}>Go</button>
              {search && (
                <button onClick={clearSearch}
                  style={{ position: 'absolute', right: 6, top: '50%', transform: 'translateY(-50%)',
                    background: '#e5e7eb', border: 'none', borderRadius: '50%', width: 20, height: 20,
                    cursor: 'pointer', fontSize: 11, color: '#6b7280',
                    display: 'flex', alignItems: 'center', justifyContent: 'center' }}>✕</button>
              )}
              {/* Autocomplete dropdown - compact */}
              {showSuggestions && suggestions.length > 0 && (
                <div style={{ position: 'absolute', top: '100%', left: 0, right: 0,
                  background: '#fff', border: '1.5px solid #e5e7eb', borderRadius: 12,
                  boxShadow: '0 8px 24px rgba(0,0,0,.12)', zIndex: 200, marginTop: 4,
                  overflow: 'hidden' }}>
                  {suggestions.map((s, i) => (
                    <button key={i} onMouseDown={() => selectSuggestion(s)}
                      style={{ width: '100%', padding: '10px 14px', background: 'none',
                        border: 'none', borderBottom: i < suggestions.length-1 ? '0.5px solid #f3f4f6' : 'none',
                        textAlign: 'left', cursor: 'pointer', display: 'flex',
                        alignItems: 'center', gap: 8, ...font }}>
                      <span style={{ fontSize: 14 }}>📍</span>
                      <div>
                        <div style={{ fontSize: 13, fontWeight: 600, color: '#111827' }}>{s.label}</div>
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Radius */}
          <div style={{ background: '#fff', padding: '8px 16px 10px', borderBottom: '0.5px solid #f3f4f6',
            display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ fontSize: 11, color: '#6b7280', fontWeight: 500 }}>Radius:</span>
            {[2, 5, 10, 15, 25].map(r => (
              <button key={r} onClick={() => updateRadius(r)}
                style={{ padding: '4px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600,
                  cursor: 'pointer', border: 'none',
                  background: radius === r ? '#f57b46' : '#f3f4f6',
                  color: radius === r ? '#fff' : '#6b7280', ...font }}>
                {r}mi
              </button>
            ))}
          </div>

          {/* Filters */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '10px 16px',
            background: '#fff', borderBottom: '0.5px solid #f3f4f6' }}>
            <span style={{ fontSize: 11, color: '#6b7280', fontWeight: 500, flexShrink: 0 }}>Filter:</span>
            <div style={{ display: 'flex', gap: 7, overflowX: 'auto', scrollbarWidth: 'none', flex: 1, minWidth: 0 }}>
            {FILTERS.map(f => (
              <div key={f.id} onClick={() => toggleFilter(f.id)}
                style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '6px 11px',
                  borderRadius: 20, whiteSpace: 'nowrap', cursor: 'pointer', flexShrink: 0,
                  border: activeFilters.has(f.id) ? '1.5px solid #f57b46' : '1.5px solid #e5e7eb',
                  background: activeFilters.has(f.id) ? '#fff3ee' : '#fff',
                  color: activeFilters.has(f.id) ? '#c2410c' : '#6b7280',
                  fontSize: 11, fontWeight: 600 }}>
                <span style={{ fontSize: 12 }}>{f.icon}</span>{f.label}
              </div>
            ))}
            </div>
          </div>

          {/* Cuisine filters — only shown when we have a couple of cuisines to choose from */}
          {cuisineOptions.length > 1 && (
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '10px 16px',
              background: '#fff', borderBottom: '0.5px solid #f3f4f6' }}>
              <span style={{ fontSize: 11, color: '#6b7280', fontWeight: 500, flexShrink: 0 }}>Cuisine:</span>
              <div style={{ display: 'flex', gap: 7, overflowX: 'auto', scrollbarWidth: 'none', flex: 1, minWidth: 0 }}>
              {cuisineOptions.map(c => (
                <div key={c} onClick={() => toggleCuisine(c)}
                  style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '6px 11px',
                    borderRadius: 20, whiteSpace: 'nowrap', cursor: 'pointer', flexShrink: 0,
                    border: activeCuisines.has(c) ? '1.5px solid #f57b46' : '1.5px solid #e5e7eb',
                    background: activeCuisines.has(c) ? '#fff3ee' : '#fff',
                    color: activeCuisines.has(c) ? '#c2410c' : '#6b7280',
                    fontSize: 11, fontWeight: 600 }}>
                  {c}
                </div>
              ))}
              </div>
            </div>
          )}

          {/* Count */}
          <div style={{ fontSize: 11, fontWeight: 600, color: '#9ca3af', padding: '10px 16px',
            textTransform: 'uppercase', letterSpacing: '.06em' }}>
            {loading
              ? 'Loading restaurants...'
              : visible.length + ' restaurant' + (visible.length !== 1 ? 's' : '') + ' within ' + radius + ' miles of ' + search}
          </div>

          {/* Skeleton cards while loading */}
          {loading && hasSearched && (
            <div style={{ padding: '0 0 16px' }}>
              <style>{`@keyframes shimmer { 0%{background-position:-200% 0} 100%{background-position:200% 0} }`}</style>
              {[1,2,3,4].map(i => (
                <div key={i} style={{ background: '#fff', borderRadius: 16,
                  overflow: 'hidden', marginBottom: 14,
                  border: '0.5px solid #e5e7eb' }}>
                  <div style={{ height: 140,
                    background: 'linear-gradient(90deg, #f0f0f0 25%, #e8e8e8 50%, #f0f0f0 75%)',
                    backgroundSize: '200% 100%', animation: 'shimmer 1.5s infinite' }} />
                  <div style={{ padding: '12px 14px' }}>
                    <div style={{ height: 18, width: '65%', borderRadius: 6, marginBottom: 8,
                      background: 'linear-gradient(90deg, #f0f0f0 25%, #e8e8e8 50%, #f0f0f0 75%)',
                      backgroundSize: '200% 100%', animation: 'shimmer 1.5s infinite' }} />
                    <div style={{ height: 12, width: '40%', borderRadius: 6, marginBottom: 10,
                      background: 'linear-gradient(90deg, #f0f0f0 25%, #e8e8e8 50%, #f0f0f0 75%)',
                      backgroundSize: '200% 100%', animation: 'shimmer 1.5s infinite' }} />
                    <div style={{ display: 'flex', gap: 6 }}>
                      {[1,2,3].map(j => (
                        <div key={j} style={{ width: 32, height: 32, borderRadius: '50%',
                          background: 'linear-gradient(90deg, #f0f0f0 25%, #e8e8e8 50%, #f0f0f0 75%)',
                          backgroundSize: '200% 100%', animation: 'shimmer 1.5s infinite' }} />
                      ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* No results */}
          {noResults && (
            <div style={{ margin: '0 16px', background: '#fff', border: '0.5px solid #e5e7eb',
              borderRadius: 14, padding: '32px 20px', textAlign: 'center' }}>
              <div style={{ fontSize: 48, marginBottom: 12 }}>🗺️</div>
              <div style={{ fontSize: 15, fontWeight: 600, color: '#111827', marginBottom: 6 }}>
                No restaurants found near {search}
              </div>
              <div style={{ fontSize: 12, color: '#6b7280', marginBottom: 20, lineHeight: 1.6 }}>
                Try a larger radius or be the first to add one and earn <strong>50 points!</strong>
              </div>
              <Link to="/add" style={{ display: 'inline-block', padding: '11px 24px',
                background: '#f57b46', color: '#fff', borderRadius: 10,
                fontSize: 13, fontWeight: 600, textDecoration: 'none' }}>
                + Add a restaurant
              </Link>
              <div style={{ marginTop: 14 }}>
                <button onClick={clearSearch}
                  style={{ background: 'none', border: 'none', color: '#6b7280',
                    fontSize: 12, cursor: 'pointer', textDecoration: 'underline', ...font }}>
                  ← Back to home
                </button>
              </div>
            </div>
          )}

          {/* Cards */}
          {!loading && !noResults && visible.length > 0 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12, padding: '0 16px 16px' }}>
              {visible.map((r, i) => {
                const verifiedAms = (r.amenities || []).filter(a => a.yes_votes >= 1 && a.yes_votes >= a.no_votes)
                const isPending = r.status === 'pending'
                return (
                  <Link key={r.id} to={'/restaurant/' + r.id} style={{ textDecoration: 'none', color: 'inherit' }}>
                    <div style={{ background: '#fff', border: '0.5px solid #e5e7eb', borderRadius: 16,
                      padding: '14px 16px', display: 'flex', gap: 14, alignItems: 'center' }}>
                      {/* Small emoji tile */}
                      <div style={{ width: 64, height: 64, borderRadius: 14, flexShrink: 0,
                        background: '#fff3ee', display: 'flex', alignItems: 'center',
                        justifyContent: 'center', fontSize: 32 }}>
                        {r.emoji || '🍽️'}
                      </div>
                      {/* Details */}
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 8 }}>
                          <div style={{ fontSize: 15, fontWeight: 600, color: '#111827',
                            overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{r.name}</div>
                          <button onClick={e => toggleFav(e, r)}
                            style={{ background: 'none', border: 'none', fontSize: 18, cursor: 'pointer',
                              color: favIds.has(r.id) ? '#f46ab8' : '#d1d5db', padding: 0, flexShrink: 0 }}>
                            {favIds.has(r.id) ? '♥' : '♡'}
                          </button>
                        </div>
                        {/* Status + cuisine + location */}
                        <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 4, minWidth: 0 }}>
                          {isPending ? (
                            <span style={{ fontSize: 10, padding: '2px 8px', borderRadius: 20, fontWeight: 600, flexShrink: 0,
                              background: '#fefae8', color: '#854d0e', border: '0.5px solid #fde9a0' }}>⏳ Pending</span>
                          ) : (
                            <span style={{ fontSize: 11, color: '#059669', fontWeight: 700, flexShrink: 0 }}>✓ Verified</span>
                          )}
                          <span style={{ fontSize: 11, color: '#6b7280',
                            overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                            {r.cuisine}{r.city ? ` · ${r.city}, ${r.state}` : ''}
                          </span>
                        </div>
                        {/* Bottom row: all confirmed amenity emojis + today's hours */}
                        {(verifiedAms.length > 0 || r.hours) && (
                          <div style={{ display: 'flex', gap: 7, flexWrap: 'wrap', alignItems: 'center', marginTop: 9 }}>
                            {verifiedAms.map(a => (
                              <span key={a.amenity_key} style={{ fontSize: 16, lineHeight: 1 }}>
                                {FILTERS.find(x => x.id === a.amenity_key)?.icon}
                              </span>
                            ))}
                            {(() => {
                              if (!r.hours) return null
                              let todayHours = null
                              try {
                                const h = JSON.parse(r.hours)
                                const today = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][new Date().getDay()]
                                todayHours = h[today] || h['Daily']
                              } catch { todayHours = r.hours }
                              return todayHours
                                ? <span style={{ fontSize: 10, color: '#9ca3af', marginLeft: 'auto' }}>{todayHours}</span>
                                : null
                            })()}
                          </div>
                        )}
                      </div>
                    </div>
                  </Link>
                )
              })}
            </div>
          )}
        </>
      )}

      {/* How to use Little Foodies — only show on home/unsearched state */}
      {!hasSearched && (
      <div style={{ margin: '32px 16px 16px', background: '#fff',
        borderRadius: 20, border: '0.5px solid #e5e7eb', overflow: 'hidden' }}>
        <div style={{ background: 'linear-gradient(135deg, #f57b46, #f46ab8)',
          padding: '16px 20px' }}>
          <div style={{ fontSize: 15, fontWeight: 800, color: '#fff',
            fontFamily: "'IntroRust', 'Georgia', serif", marginBottom: 2 }}>
            How to use Little Foodies
          </div>
          <div style={{ fontSize: 12, color: 'rgba(255,255,255,.85)' }}>
            Your guide to finding the perfect family restaurant
          </div>
        </div>
        <div style={{ padding: '16px 20px', display: 'flex', flexDirection: 'column', gap: 16 }}>
          {[
            { icon: '🔍', title: 'Search your zip code', body: 'Enter your zip to find kid-friendly restaurants nearby. Adjust the radius to see more options.' },
            { icon: '🪑', title: 'Check family amenities', body: 'Every restaurant shows community-verified info on high chairs, kids menus, changing tables, stroller access, and more.' },
            { icon: '🍟', title: 'Browse the kids menu', body: 'Tap the kids menu tile on any restaurant to see photos of the kids menu so little ones can pick before you arrive.' },
            { icon: '⚠️', title: 'Allergen info', body: 'Look for allergen badges like peanut-free and gluten-free options. Always confirm directly with the restaurant.', note: '* Community-reported, unverified until confirmed by the restaurant owner.' },
            { icon: '📤', title: 'Share with friends', body: 'Found a great spot? Tap Share on any restaurant page to send it to friends in a text message.' },
            { icon: '🏅', title: 'Earn points', body: 'Add restaurants (+50 pts), write reviews (+25 pts), vote on amenities (+5 pts), and climb the tiers from Sprout to Legend.' },
          ].map(item => (
            <div key={item.title} style={{ display: 'flex', gap: 14, alignItems: 'flex-start' }}>
              <div style={{ width: 40, height: 40, borderRadius: 12, background: '#f9fafb',
                border: '0.5px solid #e5e7eb', display: 'flex', alignItems: 'center',
                justifyContent: 'center', fontSize: 20, flexShrink: 0 }}>
                {item.icon}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: '#111827', marginBottom: 3 }}>
                  {item.title}
                </div>
                <div style={{ fontSize: 12, color: '#6b7280', lineHeight: 1.6 }}>
                  {item.body}
                </div>
                {item.note && (
                  <div style={{ fontSize: 10, color: '#9ca3af', marginTop: 4, lineHeight: 1.5 }}>
                    {item.note}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
      )}

    </div>
  )
}
